import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';

function FormAgendamento({ onNovoAgendamento, agendamentoEditando, onFimEdicao }) {
  // Tipo de atendimento: 'Novo', 'Retorno', 'Solicitar'
  const [tipoAtendimento, setTipoAtendimento] = useState('Novo');

  // Pacientes e pesquisa
  const [pacientes, setPacientes] = useState([]);
  const [buscaPaciente, setBuscaPaciente] = useState('');
  const [pacienteId, setPacienteId] = useState('');
  const [nomePaciente, setNomePaciente] = useState('');
  const [telefone, setTelefone] = useState('');
  const [showLista, setShowLista] = useState(false);

  // Listas para selects
  const [disciplinas, setDisciplinas] = useState([]);
  const [alunos, setAlunos] = useState([]);
  // Campos do formulário
  const [disciplinaId, setDisciplinaId] = useState('');
  const [data, setData] = useState('');
  const [hora, setHora] = useState('');
  const [observacoes, setObservacoes] = useState('');
  // Operador (obrigatório) e auxiliares (opcionais)
  const [operadorId, setOperadorId] = useState('');
  const [auxiliar1Id, setAuxiliar1Id] = useState('');
  const [auxiliar2Id, setAuxiliar2Id] = useState('');
  // Mensagem de sucesso/erro
  const [mensagem, setMensagem] = useState('');

  // Ref para pesquisa de paciente
  const inputRef = useRef(null);

  // Carrega listas iniciais
  useEffect(() => {
    axios.get('/api/pacientes').then(res => setPacientes(res.data));
    axios.get('/api/disciplinas').then(res => setDisciplinas(res.data));
    axios.get('/api/alunos').then(res => setAlunos(res.data));
  }, []);

  // Fecha lista ao clicar fora
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (inputRef.current && !inputRef.current.contains(event.target)) {
        setShowLista(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // Preencher dados se editando
  useEffect(() => {
    if (agendamentoEditando) {
      setTipoAtendimento(
        agendamentoEditando.status === 'Solicitado'
          ? 'Solicitar'
          : agendamentoEditando.status
      );
      setDisciplinaId(String(agendamentoEditando.disciplina_id || ''));
      setPacienteId(agendamentoEditando.paciente_id || '');
      setNomePaciente(agendamentoEditando.nome_paciente || '');
      setTelefone(agendamentoEditando.telefone || '');
      setData(agendamentoEditando.data ? agendamentoEditando.data.slice(0, 10) : '');
      setHora(agendamentoEditando.hora || '19:00');
      setObservacoes(agendamentoEditando.observacoes || '');
      setOperadorId(
        agendamentoEditando.aluno_id
          ? String(agendamentoEditando.aluno_id)
          : agendamentoEditando.operador_id || ''
      );
      setAuxiliar1Id(
        agendamentoEditando.auxiliar1_id
          ? String(agendamentoEditando.auxiliar1_id)
          : ''
      );
      setAuxiliar2Id(
        agendamentoEditando.auxiliar2_id
          ? String(agendamentoEditando.auxiliar2_id)
          : ''
      );
     // **Aqui está o detalhe:**
    // Monta buscaPaciente como nome + telefone (igual quando seleciona paciente)
    setBuscaPaciente(
      (agendamentoEditando.nome_paciente || agendamentoEditando.pacienteNome || '') +
      (agendamentoEditando.telefone ? ' - ' + agendamentoEditando.telefone : '')
    );
    setShowLista(false);
  } else {
    // ... restante igual
    setTipoAtendimento('Novo');
    setDisciplinaId('');
    setPacienteId('');
    setNomePaciente('');
    setTelefone('');
    setData('');
    setHora('19:00');
    setObservacoes('');
    setOperadorId('');
    setAuxiliar1Id('');
    setAuxiliar2Id('');
    setBuscaPaciente('');
    setShowLista(false);
  }
}, [agendamentoEditando]);

  // Filtro dos pacientes para pesquisa (nome OU telefone)
  const pacientesFiltrados = pacientes.filter(p => {
    const busca = buscaPaciente.toLowerCase();
    return (
      p.nome.toLowerCase().includes(busca) ||
      (p.telefone && p.telefone.includes(busca))
    );
  });

  // Seleciona paciente da lista
  const handleSelecionarPaciente = (paciente) => {
    setPacienteId(paciente.id);
    setNomePaciente(paciente.nome);
    setTelefone(paciente.telefone);
    setBuscaPaciente(paciente.nome + (paciente.telefone ? ' - ' + paciente.telefone : ''));
    setShowLista(false);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!disciplinaId) { setMensagem("Disciplina obrigatória"); return; }
    if (!pacienteId && tipoAtendimento !== 'Solicitar') { setMensagem("Paciente obrigatório"); return; }
    if (!operadorId) { setMensagem("Selecione um operador"); return; }

   const dados = {
  disciplina_id: disciplinaId,
  paciente_id: tipoAtendimento === 'Solicitar' ? null : pacienteId,
  nome_paciente: tipoAtendimento === 'Solicitar' ? null : nomePaciente,
  telefone: tipoAtendimento === 'Solicitar' ? null : telefone,
  data, // Sempre envia a data do formulário!
  hora, // Sempre envia a hora do formulário!
  observacoes: tipoAtendimento === 'Solicitar' ? null : observacoes,
  aluno_id: operadorId,
  auxiliar1_id: auxiliar1Id,
  auxiliar2_id: auxiliar2Id,
  status: tipoAtendimento === 'Solicitar' ? 'Solicitado' : tipoAtendimento,
  solicitado_por_recepcao: tipoAtendimento === 'Solicitar',
};


    // POST se novo, PUT se edição
    if (agendamentoEditando) {
      axios.put(`/api/agendamentos/${agendamentoEditando.id}`, dados)
        .then(() => {
          setMensagem('Agendamento atualizado!');
          onNovoAgendamento && onNovoAgendamento();
          onFimEdicao && onFimEdicao();
        })
        .catch(() => setMensagem('Erro ao atualizar agendamento.'));
    } else {
      axios.post('/api/agendamentos', dados)
        .then(() => {
          setMensagem('Agendamento cadastrado!');
          onNovoAgendamento && onNovoAgendamento();
          // Limpa o formulário
          setDisciplinaId('');
          setPacienteId('');
          setNomePaciente('');
          setTelefone('');
          setData('');
          setHora('');
          setObservacoes('');
          setOperadorId('');
          setAuxiliar1Id('');
          setAuxiliar2Id('');
          setBuscaPaciente('');
        })
        .catch(() => setMensagem('Erro ao cadastrar agendamento.'));
    }
  };

  // === INÍCIO DO JSX ===
  return (
    <div className="bg-white mx-auto">
      <form onSubmit={handleSubmit}>
        <h2 className="text-2xl font-bold mb-6 text-gray-800">Agendar Paciente</h2>
        {/* Tipo de atendimento */}
        <div className="flex gap-2 mb-4">
          {['Novo', 'Retorno', 'Solicitar'].map((tipo) => (
            <button
              key={tipo}
              type="button"
              onClick={() => setTipoAtendimento(tipo)}
              className={`px-4 py-1 rounded-full font-semibold transition 
                ${tipoAtendimento === tipo 
                  ? 'bg-[#D9E0FF] text-gray-800'
                  : 'bg-gray-200 text-gray-800 hover:bg-gray-300'}`
              }
            >
              {tipo === 'Solicitar' ? 'Solicitar para Recepção' : tipo}
            </button>
          ))}
        </div>
        {/* Disciplina */}
        <div>
          <label className="block mb-1 font-medium">Disciplina</label>
          <div className="flex flex-wrap gap-2">
            {disciplinas.map(d => (
              <button
                key={d.id}
                type="button"
                className={`px-4 py-1 rounded-full border transition ${
                  disciplinaId === String(d.id)
                    ? "bg-[#D9E0FF] text-gray-800  font-semibold"
                    : "bg-gray-100 text-gray-800  hover:bg-gray-300"
                }`}
                onClick={() => setDisciplinaId(String(d.id))}
              >
                {d.nome}
              </button>
            ))}
          </div>
          {disciplinaId === '' && (
            <span className="text-red-600 text-xs mt-2 block">Selecione uma disciplina</span>
          )}
        </div>
        {/* Paciente */}
        {tipoAtendimento !== 'Solicitar' && (
          <div className="relative my-4" ref={inputRef}>
            <label className="block mb-1 font-medium">Paciente</label>
            <input
  className="w-full border rounded px-3 py-2"
  placeholder="Digite nome ou telefone para buscar"
  value={buscaPaciente}
  onChange={e => {
    setBuscaPaciente(e.target.value);
    setShowLista(true);
    setPacienteId(''); // Limpa pacienteId se o texto mudou
  }}
  onFocus={() => setShowLista(true)}
  required
/>
            {/* Dropdown de pacientes */}
            {showLista && buscaPaciente && (
              <ul className="absolute z-10 bg-white border w-full rounded shadow max-h-40 overflow-y-auto">
                {pacientesFiltrados.length > 0 ? (
                  pacientesFiltrados.map(p => (
                    <li
                      key={p.id}
                      className="px-3 py-2 cursor-pointer hover:bg-blue-100"
                      onClick={() => handleSelecionarPaciente(p)}
                    >
                      {p.nome} - {p.telefone}
                    </li>
                  ))
                ) : (
                  <li className="px-3 py-2 text-gray-400">Nenhum paciente encontrado</li>
                )}
              </ul>
            )}
            {/* Mostrar nome/telefone selecionado, apenas leitura */}
            {pacienteId && (
              <div className="mt-2 flex flex-col gap-2">
                <input
                  className="border rounded px-3 py-2 bg-gray-100"
                  value={nomePaciente}
                  readOnly
                />
                <input
                  className="border rounded px-3 py-2 bg-gray-100"
                  value={telefone}
                  readOnly
                />
              </div>
            )}
          </div>
        )}
        {/* Data e Hora */}
        <div className="flex flex-col md:flex-row gap-4">
  <div className="flex-col">
    <label className="block mb-1 font-medium">Data do Atendimento</label>
    <input
      type="date"
      className="w-[200px] border rounded-full px-3 py-1"
      value={data}
      onChange={e => setData(e.target.value)}
      required
    />
  </div>
  <div className="flex-1">
    <label className="block mb-1 font-medium">Hora do Atendimento</label>
    <input
      type="time"
      className="w-[200px] border rounded-full px-3 py-1"
      value={hora}
      onChange={e => setHora(e.target.value)}
      required
    />
  </div>
</div>

        {/* Observações */}
        <div>
          <label className="block mb-1 my-4 font-medium">Outras Informações</label>
          <textarea
            className="w-full border rounded px-3 py-2"
            value={observacoes}
            onChange={e => setObservacoes(e.target.value)}
            placeholder="Observações relevantes"
          />
        </div>
        {/* Alunos */}
        <div>
          <label className="block mb-4 my-4 font-medium">Alunos que irão realizar o atendimento</label>
          <div className="flex-1 flex-col md:flex-row gap-4">
            <div className="flex-1">
              <label className="block mb-1 text-sm font-semibold">Operador</label>
              <select
                required
                className="w-full border rounded px-3 py-2"
                value={operadorId}
                onChange={e => setOperadorId(e.target.value)}
              >
                <option value="">Nome completo do operador</option>
                {alunos.map(a => (
                  <option key={a.id} value={a.id}>{a.nome}</option>
                ))}
              </select>
            </div>
            <div className="flex-1 my-4 ">
              <label className="block mb-1 text-sm font-semibold">Auxiliar</label>
              <select
                className="w-full border rounded px-3 py-2"
                value={auxiliar1Id}
                onChange={e => setAuxiliar1Id(e.target.value)}
              >
                <option value="">Nome completo do auxiliar</option>
                {alunos.map(a => (
                  <option key={a.id} value={a.id}>{a.nome}</option>
                ))}
              </select>
            </div>

          </div>
        </div>
        {/* Botão */}
        <div className="mt-8 flex">
          <button
            type="submit"
            className="bg-[#3172C0] hover:bg-[#083A76] text-white font-bold py-2 px-6 rounded-full"
          >
            {tipoAtendimento === 'Solicitar' ? 'Solicitar para Recepção' : 'Agendar Paciente'}
          </button>
          {agendamentoEditando && (
            <button
              type="button"
              className="ml-4 bg-[#DA3648] text-white hover:bg-[#BC3140] px-4 py-2 rounded-full"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>
        {/* Mensagem */}
        {mensagem && <p className="mt-4 text-red-600">{mensagem}</p>}
      </form>
    </div>
  );
}

export default FormAgendamento;
